import httpx

from app.core.config import settings

HRFLOW_BASE_URL = "https://api.hrflow.ai/v1"


class HrFlowClient:
    """Low-level async HTTP client for the HrFlow API."""

    def __init__(self, api_key: str | None = None, user_email: str | None = None):
        self.base_url = HRFLOW_BASE_URL
        self._headers = {
            "accept": "application/json",
            "content-type": "application/json",
            "X-API-KEY": api_key or settings.api_key,
            "X-USER-EMAIL": user_email or settings.user_email,
        }

    def _client(self) -> httpx.AsyncClient:
        return httpx.AsyncClient(base_url=self.base_url, headers=self._headers, timeout=10.0)

    async def get(self, path: str, params: dict | None = None) -> dict:
        async with self._client() as client:
            response = await client.get(path, params=params)
            response.raise_for_status()
            return response.json()

    async def post(self, path: str, json: dict | None = None) -> dict:
        async with self._client() as client:
            response = await client.post(path, json=json)
            response.raise_for_status()
            return response.json()

    async def patch(self, path: str, json: dict | None = None) -> dict:
        async with self._client() as client:
            response = await client.patch(path, json=json)
            response.raise_for_status()
            return response.json()

    async def check_auth(self) -> dict:
        """Call GET /auth to validate credentials and get workspace info."""
        return await self.get("/auth")

