import { useState } from 'react'
import { setupJobInterview, type SetupJobResponse } from '../api/hrflow'

interface Props {
  onComplete: (result: SetupJobResponse) => void
}

export default function RhSetupPage({ onComplete }: Props) {
  const [title, setTitle] = useState('')
  const [text, setText] = useState('')
  const [questionCount, setQuestionCount] = useState(5)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError(null)
    setLoading(true)
    try {
      const result = await setupJobInterview({ text, title, question_count: questionCount })
      onComplete(result)
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Une erreur est survenue')
    } finally {
      setLoading(false)
    }
  }

  return (
    <main className="min-h-screen bg-slate-950 text-slate-50 flex items-center justify-center px-6 py-16">
      <div className="w-full max-w-2xl space-y-8">
        {/* Header */}
        <div className="space-y-2">
          <span className="inline-flex rounded-full border border-slate-800 bg-slate-900 px-3 py-1 text-xs text-slate-400 tracking-wide uppercase">
            Espace recruteur
          </span>
          <h1 className="text-3xl font-semibold tracking-tight">Créer une session d'entretien</h1>
          <p className="text-slate-400 text-sm">
            Collez votre offre d'emploi, choisissez le nombre de questions techniques et lancez la génération.
          </p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          {/* Titre du poste */}
          <div className="space-y-2">
            <label className="block text-sm font-medium text-slate-300">
              Intitulé du poste
            </label>
            <input
              type="text"
              value={title}
              onChange={e => setTitle(e.target.value)}
              placeholder="ex : Développeur Python Senior"
              required
              className="w-full rounded-lg border border-slate-700 bg-slate-900 px-4 py-2.5 text-slate-50 placeholder-slate-500 focus:border-teal-500 focus:outline-none focus:ring-1 focus:ring-teal-500 transition"
            />
          </div>

          {/* Offre d'emploi */}
          <div className="space-y-2">
            <label className="block text-sm font-medium text-slate-300">
              Offre d'emploi
            </label>
            <textarea
              value={text}
              onChange={e => setText(e.target.value)}
              placeholder="Collez ici le texte complet de l'offre d'emploi…"
              required
              rows={10}
              className="w-full rounded-lg border border-slate-700 bg-slate-900 px-4 py-3 text-slate-50 placeholder-slate-500 focus:border-teal-500 focus:outline-none focus:ring-1 focus:ring-teal-500 transition resize-none font-mono text-sm leading-relaxed"
            />
          </div>

          {/* Slider */}
          <div className="space-y-3">
            <div className="flex items-center justify-between">
              <label className="text-sm font-medium text-slate-300">
                Nombre de questions techniques
              </label>
              <span className="tabular-nums text-2xl font-semibold text-teal-400">
                {questionCount}
              </span>
            </div>
            <input
              type="range"
              min={1}
              max={20}
              value={questionCount}
              onChange={e => setQuestionCount(Number(e.target.value))}
              className="w-full h-1.5 rounded-full appearance-none cursor-pointer bg-slate-700 accent-teal-500"
            />
            <div className="flex justify-between text-xs text-slate-500">
              <span>1</span>
              <span>20</span>
            </div>
          </div>

          {/* Erreur */}
          {error && (
            <p className="rounded-lg border border-red-800 bg-red-950 px-4 py-3 text-sm text-red-400">
              {error}
            </p>
          )}

          {/* Submit */}
          <button
            type="submit"
            disabled={loading}
            className="w-full rounded-lg bg-teal-600 px-6 py-3 text-sm font-semibold text-white hover:bg-teal-500 disabled:cursor-not-allowed disabled:opacity-50 transition-colors"
          >
            {loading ? (
              <span className="flex items-center justify-center gap-2">
                <svg className="h-4 w-4 animate-spin" viewBox="0 0 24 24" fill="none">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8H4z" />
                </svg>
                Génération en cours…
              </span>
            ) : (
              'Suivant →'
            )}
          </button>
        </form>
      </div>
    </main>
  )
}

