            className="rounded-lg bg-teal-600 px-6 py-2.5 text-sm font-semibold text-white hover:bg-teal-500 disabled:cursor-not-allowed disabled:opacity-40 transition-colors"
          >
            Continuer →
          </button>
        </div>
      </div>
