import { useState } from 'react'
import { setupJobInterview, type SetupJobResponse } from '../api/hrflow'

interface Props {
  onComplete: (result: SetupJobResponse) => void
}

export default function RhSetupPage({ onComplete }: Props) {
  const [title, setTitle] = useState('')
  const [text, setText] = useState('')
  const [questionCount, setQuestionCount] = useState(5)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError(null)
    setLoading(true)
    try {
      const result = await setupJobInterview({ text, title, question_count: questionCount })
      onComplete(result)
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Une erreur est survenue')
    } finally {
      setLoading(false)
    }
  }

  const sliderPercent = ((questionCount - 1) / 19) * 100

  return (
    <main className="min-h-screen bg-slate-950 text-slate-50 flex items-start justify-center px-6 py-16">
      <div className="w-full max-w-2xl space-y-10">

        {/* Header */}
        <div className="space-y-3">
          <div className="flex items-center gap-2">
            <span className="h-2 w-2 rounded-full bg-teal-400" />
            <span className="text-xs font-medium tracking-widest uppercase text-slate-400">
              Espace recruteur
            </span>
          </div>
          <h1 className="text-4xl font-bold tracking-tight">
            Nouvelle session<br />
            <span className="text-teal-400">d'entretien</span>
          </h1>
          <p className="text-slate-400 text-sm max-w-md">
            Collez votre offre d'emploi, choisissez le nombre de questions et laissez l'IA faire le reste.
          </p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-7">

          {/* Titre */}
          <div className="space-y-2">
            <label className="block text-xs font-semibold uppercase tracking-widest text-slate-400">
              Intitulé du poste
            </label>
            <input
              type="text"
              value={title}
              onChange={e => setTitle(e.target.value)}
              placeholder="ex : Développeur Python Senior"
              required
              className="w-full rounded-xl border border-slate-700 bg-slate-900 px-4 py-3 text-slate-50 placeholder-slate-600 focus:border-teal-500 focus:outline-none focus:ring-2 focus:ring-teal-500/30 transition-all"
            />
          </div>

          {/* Offre */}
          <div className="space-y-2">
            <label className="block text-xs font-semibold uppercase tracking-widest text-slate-400">
              Offre d'emploi
            </label>
            <textarea
              value={text}
              onChange={e => setText(e.target.value)}
              placeholder="Collez ici le texte complet de l'offre…"
              required
              rows={10}
              className="w-full rounded-xl border border-slate-700 bg-slate-900 px-4 py-3 text-slate-50 placeholder-slate-600 focus:border-teal-500 focus:outline-none focus:ring-2 focus:ring-teal-500/30 transition-all resize-none text-sm leading-relaxed font-mono"
            />
          </div>

          {/* Slider */}
          <div className="rounded-xl border border-slate-800 bg-slate-900 px-5 py-5 space-y-4">
            <div className="flex items-center justify-between">
              <span className="text-xs font-semibold uppercase tracking-widest text-slate-400">
                Questions techniques
              </span>
              <span className="text-3xl font-bold tabular-nums text-teal-400">
                {questionCount}
              </span>
            </div>

            {/* Track custom */}
            <div className="relative h-6 flex items-center">
              {/* Fond de la piste */}
              <div className="absolute inset-x-0 h-1.5 rounded-full bg-slate-700" />
              {/* Remplissage */}
              <div
                className="absolute left-0 h-1.5 rounded-full bg-teal-500 transition-all"
                style={{ width: `${sliderPercent}%` }}
              />
              <input
                type="range"
                min={1}
                max={20}
                value={questionCount}
                onChange={e => setQuestionCount(Number(e.target.value))}
                className="relative w-full appearance-none bg-transparent cursor-pointer
                  [&::-webkit-slider-thumb]:appearance-none
                  [&::-webkit-slider-thumb]:h-5
                  [&::-webkit-slider-thumb]:w-5
                  [&::-webkit-slider-thumb]:rounded-full
                  [&::-webkit-slider-thumb]:bg-white
                  [&::-webkit-slider-thumb]:shadow-md
                  [&::-webkit-slider-thumb]:border-2
                  [&::-webkit-slider-thumb]:border-teal-500
                  [&::-webkit-slider-thumb]:transition-transform
                  [&::-webkit-slider-thumb]:hover:scale-110
                  [&::-moz-range-thumb]:h-5
                  [&::-moz-range-thumb]:w-5
                  [&::-moz-range-thumb]:rounded-full
                  [&::-moz-range-thumb]:bg-white
                  [&::-moz-range-thumb]:border-2
                  [&::-moz-range-thumb]:border-teal-500
                  [&::-moz-range-thumb]:cursor-pointer"
              />
            </div>

            <div className="flex justify-between text-xs text-slate-600 font-mono">
              {[1, 5, 10, 15, 20].map(v => (
                <span key={v}>{v}</span>
              ))}
            </div>
          </div>

          {/* Erreur */}
          {error && (
            <div className="flex items-start gap-3 rounded-xl border border-red-800/60 bg-red-950/40 px-4 py-3">
              <span className="mt-0.5 text-red-400">⚠</span>
              <p className="text-sm text-red-300">{error}</p>
            </div>
          )}

          {/* Submit */}
          <button
            type="submit"
            disabled={loading}
            className="w-full rounded-xl bg-teal-600 px-6 py-3.5 text-sm font-bold tracking-wide text-white hover:bg-teal-500 active:scale-[0.99] disabled:cursor-not-allowed disabled:opacity-50 transition-all"
          >
            {loading ? (
              <span className="flex items-center justify-center gap-2">
                <svg className="h-4 w-4 animate-spin" viewBox="0 0 24 24" fill="none">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8H4z" />
                </svg>
                Analyse et génération en cours…
              </span>
            ) : (
              'Générer les questions →'
            )}
          </button>
        </form>
      </div>
    </main>
  )
}

