import { useState } from 'react'
import { setupJobInterview, type SetupJobResponse } from '../api/hrflow'

interface Props {
  onComplete: (result: SetupJobResponse) => void
}

export default function RhSetupPage({ onComplete }: Props) {
  const [title, setTitle] = useState('')
  const [text, setText] = useState('')
  const [questionCount, setQuestionCount] = useState(5)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)

  async function handleSubmit(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault()
    setError(null)
    setLoading(true)
    try {
      const result = await setupJobInterview({ text, title, question_count: questionCount })
      onComplete(result)
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Une erreur est survenue')
    } finally {
      setLoading(false)
    }
  }

  const sliderPercent = ((questionCount - 1) / 19) * 100

  return (
    <main className="min-h-screen bg-slate-950 text-slate-50 flex items-start justify-center px-6 py-16">
      <div className="w-full max-w-2xl space-y-10">

        {/* Header */}
        <div className="space-y-3">
          <div className="flex items-center gap-2">
            <span className="h-2 w-2 rounded-full bg-teal-400" />
            <span className="text-xs font-medium tracking-widest uppercase text-slate-400">
              Espace recruteur
            </span>
          </div>
          <h1 className="text-4xl font-bold tracking-tight">
            Nouvelle session<br />
            <span className="text-teal-400">d'entretien</span>
          </h1>
          <p className="text-slate-400 text-sm max-w-md">
            Collez votre offre d'emploi, choisissez le nombre de questions et laissez l'IA faire le reste.
          </p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-7">

          {/* Titre */}
          <div className="space-y-2">
            <label className="block text-xs font-semibold uppercase tracking-widest text-slate-400">
              Intitulé du poste
            </label>
            <input
              type="text"
              value={title}
              onChange={e => setTitle(e.target.value)}
              placeholder="ex : Développeur Python Senior"
              required
              className="w-full rounded-xl border border-slate-700 bg-slate-900 px-4 py-3 text-slate-50 placeholder-slate-600 focus:border-teal-500 focus:outline-none focus:ring-2 focus:ring-teal-500/30 transition-all"
            />
          </div>

          {/* Offre */}
          <div className="space-y-2">
            <label className="block text-xs font-semibold uppercase tracking-widest text-slate-400">
              Offre d'emploi
            </label>
            <textarea
              value={text}
              onChange={e => setText(e.target.value)}
              placeholder="Collez ici le texte complet de l'offre…"
              required
              rows={10}
              className="w-full rounded-xl border border-slate-700 bg-slate-900 px-4 py-3 text-slate-50 placeholder-slate-600 focus:border-teal-500 focus:outline-none focus:ring-2 focus:ring-teal-500/30 transition-all resize-none text-sm leading-relaxed font-mono"
            />
          </div>

          {/* Slider */}
          <div className="rounded-xl border border-slate-800 bg-slate-900 px-5 py-5 space-y-4">
            <div className="flex items-center justify-between">
              <span className="text-xs font-semibold uppercase tracking-widest text-slate-400">
                Questions techniques
              </span>
              <span className="text-3xl font-bold tabular-nums text-teal-400">
                {questionCount}
              </span>
            </div>

            {/* Track custom */}
            <div className="relative h-6 flex items-center">
              {/* Fond de la piste */}
              <div className="absolute inset-x-0 h-1.5 rounded-full bg-slate-700" />
              {/* Remplissage */}
              <div
                className="absolute left-0 h-1.5 rounded-full bg-teal-500 transition-all"
                style={{ width: `${sliderPercent}%` }}
              />
              <input
                type="range"
                min={1}
                max={20}
                value={questionCount}
                onChange={e => setQuestionCount(Number(e.target.value))}
                className="relative w-full appearance-none bg-transparent cursor-pointer
                  [&::-webkit-slider-thumb]:appearance-none
                  [&::-webkit-slider-thumb]:h-5
                  [&::-webkit-slider-thumb]:w-5
                  [&::-webkit-slider-thumb]:rounded-full
                  [&::-webkit-slider-thumb]:bg-white
                  [&::-webkit-slider-thumb]:shadow-md
                  [&::-webkit-slider-thumb]:border-2
                  [&::-webkit-slider-thumb]:border-teal-500
                  [&::-webkit-slider-thumb]:transition-transform
                  [&::-webkit-slider-thumb]:hover:scale-110
                  [&::-moz-range-thumb]:h-5
                  [&::-moz-range-thumb]:w-5
                  [&::-moz-range-thumb]:rounded-full
                  [&::-moz-range-thumb]:bg-white
                  [&::-moz-range-thumb]:border-2
                  [&::-moz-range-thumb]:border-teal-500
                  [&::-moz-range-thumb]:cursor-pointer"
              />
            </div>

            <div className="flex justify-between text-xs text-slate-600 font-mono">
              {[1, 5, 10, 15, 20].map(v => (
                <span key={v}>{v}</span>
              ))}
            </div>
          </div>

          {/* Erreur */}
          {error && (
            <div className="flex items-start gap-3 rounded-xl border border-red-800/60 bg-red-950/40 px-4 py-3">
              <span className="mt-0.5 text-red-400">⚠</span>
              <p className="text-sm text-red-300">{error}</p>
            </div>
          )}

          {/* Submit */}
          <button
            type="submit"
            disabled={loading}
            className="w-full rounded-xl bg-teal-600 px-6 py-3.5 text-sm font-bold tracking-wide text-white hover:bg-teal-500 active:scale-[0.99] disabled:cursor-not-allowed disabled:opacity-50 transition-all"
          >
            {loading ? (
              <span className="flex items-center justify-center gap-2">
                <svg className="h-4 w-4 animate-spin" viewBox="0 0 24 24" fill="none">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8H4z" />
                </svg>
                Analyse et génération en cours…
              </span>
            ) : (
              'Générer les questions →'
            )}
          </button>
        </form>
      </div>
    </main>
  )
}

import { useState } from 'react'
import type { SetupJobResponse } from '../api/hrflow'

interface Props {
  result: SetupJobResponse
  onBack: () => void
  onContinue: (questions: string[]) => void
}

export default function RhQuestionsPage({ result, onBack, onContinue }: Props) {
  const [questions, setQuestions] = useState<string[]>(result.questions)
  const [newQuestion, setNewQuestion] = useState('')

  function deleteQuestion(index: number) {
    setQuestions(prev => prev.filter((_, i) => i !== index))
  }

  function addQuestion() {
    const trimmed = newQuestion.trim()
    if (!trimmed) return
    setQuestions(prev => [...prev, trimmed])
    setNewQuestion('')
  }

  function handleAddKeyDown(e: React.KeyboardEvent) {
    if (e.key === 'Enter') {
      e.preventDefault()
      addQuestion()
    }
  }

  return (
    <main className="min-h-screen bg-slate-950 text-slate-50 flex items-center justify-center px-6 py-16">
      <div className="w-full max-w-2xl space-y-8">
        {/* Header */}
        <div className="space-y-2">
          <button
            onClick={onBack}
            className="text-xs text-slate-500 hover:text-slate-300 transition-colors flex items-center gap-1"
          >
            ← Retour
          </button>
          <h1 className="text-3xl font-semibold tracking-tight">Questions techniques</h1>
          <p className="text-slate-400 text-sm">
            Référence job :{' '}
            <span className="font-mono text-slate-300">{result.job_reference}</span>
          </p>
          <p className="text-slate-500 text-xs">
            Modifiez, supprimez ou ajoutez des questions avant de continuer.
          </p>
        </div>

        {/* Liste des questions */}
        <div className="space-y-3">
          {questions.length === 0 && (
            <p className="text-slate-500 text-sm italic">Aucune question. Ajoutez-en une ci-dessous.</p>
          )}
          {questions.map((q, i) => (
            <div
              key={i}
              className="group flex items-start gap-3 rounded-lg border border-slate-800 bg-slate-900 px-4 py-3"
            >
              <span className="mt-0.5 flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-teal-900 text-xs font-semibold text-teal-400">
                {i + 1}
              </span>
              <p className="flex-1 text-sm leading-relaxed text-slate-200">{q}</p>
              <button
                onClick={() => deleteQuestion(i)}
                title="Supprimer"
                className="shrink-0 text-slate-600 hover:text-red-400 transition-colors opacity-0 group-hover:opacity-100"
              >
                <svg className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zm-1 7a1 1 0 012 0v4a1 1 0 11-2 0V9zm4 0a1 1 0 012 0v4a1 1 0 11-2 0V9z" clipRule="evenodd" />
                </svg>
              </button>
            </div>
          ))}
        </div>

        {/* Ajouter une question */}
        <div className="space-y-2">
          <label className="block text-xs font-medium text-slate-400 uppercase tracking-wide">
            Ajouter une question
          </label>
          <div className="flex gap-2">
            <input
              type="text"
              value={newQuestion}
              onChange={e => setNewQuestion(e.target.value)}
              onKeyDown={handleAddKeyDown}
              placeholder="Écrivez une question puis appuyez sur Entrée…"
              className="flex-1 rounded-lg border border-slate-700 bg-slate-900 px-4 py-2.5 text-sm text-slate-50 placeholder-slate-500 focus:border-teal-500 focus:outline-none focus:ring-1 focus:ring-teal-500 transition"
            />
            <button
              onClick={addQuestion}
              className="rounded-lg border border-slate-700 bg-slate-900 px-4 py-2.5 text-sm text-slate-300 hover:border-teal-600 hover:text-teal-400 transition-colors"
            >
              +
            </button>
          </div>
        </div>

        {/* Actions */}
        <div className="flex items-center justify-between pt-2">
          <span className="text-xs text-slate-500">
            {questions.length} question{questions.length !== 1 ? 's' : ''}
          </span>
          <button
            onClick={() => onContinue(questions)}
            disabled={questions.length === 0}
            className="rounded-lg bg-teal-600 px-6 py-2.5 text-sm font-semibold text-white hover:bg-teal-500 disabled:cursor-not-allowed disabled:opacity-40 transition-colors"
          >
            Continuer →
          </button>
        </div>
      </div>
    </main>
  )
}

