              </span>
            ) : (
              'Générer les questions →'
            )}
          </button>
        </form>
      </div>
    </main>
  )
}

import { useState } from 'react'
import type { SetupJobResponse } from '../api/hrflow'

interface Props {
  result: SetupJobResponse
  onBack: () => void
  onContinue: (questions: string[]) => void
}

export default function RhQuestionsPage({ result, onBack, onContinue }: Props) {
  const [questions, setQuestions] = useState<string[]>(result.questions)
  const [newQuestion, setNewQuestion] = useState('')

  function deleteQuestion(index: number) {
    setQuestions(prev => prev.filter((_, i) => i !== index))
  }

  function addQuestion() {
    const trimmed = newQuestion.trim()
    if (!trimmed) return
    setQuestions(prev => [...prev, trimmed])
    setNewQuestion('')
  }

  function handleAddKeyDown(e: React.KeyboardEvent) {
    if (e.key === 'Enter') {
      e.preventDefault()
      addQuestion()
    }
  }

  return (
    <main className="min-h-screen bg-slate-950 text-slate-50 flex items-center justify-center px-6 py-16">
      <div className="w-full max-w-2xl space-y-8">
        {/* Header */}
        <div className="space-y-2">
          <button
            onClick={onBack}
            className="text-xs text-slate-500 hover:text-slate-300 transition-colors flex items-center gap-1"
          >
            ← Retour
          </button>
          <h1 className="text-3xl font-semibold tracking-tight">Questions techniques</h1>
          <p className="text-slate-400 text-sm">
            Référence job :{' '}
            <span className="font-mono text-slate-300">{result.job_reference}</span>
          </p>
          <p className="text-slate-500 text-xs">
            Modifiez, supprimez ou ajoutez des questions avant de continuer.
          </p>
        </div>

        {/* Liste des questions */}
        <div className="space-y-3">
          {questions.length === 0 && (
            <p className="text-slate-500 text-sm italic">Aucune question. Ajoutez-en une ci-dessous.</p>
          )}
          {questions.map((q, i) => (
            <div
              key={i}
              className="group flex items-start gap-3 rounded-lg border border-slate-800 bg-slate-900 px-4 py-3"
            >
              <span className="mt-0.5 flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-teal-900 text-xs font-semibold text-teal-400">
                {i + 1}
              </span>
              <p className="flex-1 text-sm leading-relaxed text-slate-200">{q}</p>
              <button
                onClick={() => deleteQuestion(i)}
                title="Supprimer"
                className="shrink-0 text-slate-600 hover:text-red-400 transition-colors opacity-0 group-hover:opacity-100"
              >
                <svg className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zm-1 7a1 1 0 012 0v4a1 1 0 11-2 0V9zm4 0a1 1 0 012 0v4a1 1 0 11-2 0V9z" clipRule="evenodd" />
                </svg>
              </button>
            </div>
          ))}
        </div>

        {/* Ajouter une question */}
        <div className="space-y-2">
          <label className="block text-xs font-medium text-slate-400 uppercase tracking-wide">
            Ajouter une question
          </label>
          <div className="flex gap-2">
            <input
              type="text"
              value={newQuestion}
              onChange={e => setNewQuestion(e.target.value)}
              onKeyDown={handleAddKeyDown}
              placeholder="Écrivez une question puis appuyez sur Entrée…"
              className="flex-1 rounded-lg border border-slate-700 bg-slate-900 px-4 py-2.5 text-sm text-slate-50 placeholder-slate-500 focus:border-teal-500 focus:outline-none focus:ring-1 focus:ring-teal-500 transition"
            />
            <button
              onClick={addQuestion}
              className="rounded-lg border border-slate-700 bg-slate-900 px-4 py-2.5 text-sm text-slate-300 hover:border-teal-600 hover:text-teal-400 transition-colors"
            >
              +
            </button>
          </div>
        </div>

        {/* Actions */}
        <div className="flex items-center justify-between pt-2">
          <span className="text-xs text-slate-500">
            {questions.length} question{questions.length !== 1 ? 's' : ''}
          </span>
          <button
            onClick={() => onContinue(questions)}
            disabled={questions.length === 0}
            className="rounded-lg bg-teal-600 px-6 py-2.5 text-sm font-semibold text-white hover:bg-teal-500 disabled:cursor-not-allowed disabled:opacity-40 transition-colors"
          >
            Continuer →
          </button>
        </div>
      </div>
    </main>
  )
}

